#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
int n;
int graph[MAXN][MAXN];
int visited[MAXN];
int max_len = 0;
void dfs(int node, int len) {
    visited[node] = 1;
    if (len > max_len) max_len = len;
    for (int i = 1; i <= n; i++) {
        if (graph[node][i] && !visited[i]) dfs(i, len + 1);
    }
    visited[node] = 0;
}
int main() {
    scanf("%d", &n);
    for (int i = 1; i < n; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        graph[u][v] = graph[v][u] = 1;
    }
    dfs(1, 0);
    printf("%d\n", max_len);
    return 0;
}

