}

code.Java:
import java.util.ArrayList;
import java.util.Scanner;
public class Main {
    static final int MAXN = 100005;
    static int n;
    static ArrayList<Integer>[] graph = new ArrayList[MAXN];
    static boolean[] visited = new boolean[MAXN];
    static int max_len = 0;
    public static void dfs(int node, int len) {
        visited[node] = true;
        if (len > max_len) max_len = len;
        for (int i : graph[node]) {
            if (!visited[i]) dfs(i, len + 1);
        }
        visited[node] = false;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        n = sc.nextInt();
        for (int i = 1; i < n; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            if (graph[u] == null) graph[u] = new ArrayList<>();
            if (graph[v] == null) graph[v] = new ArrayList<>();
            graph[u].add(v);
            graph[v].add(u);
        }
        dfs(1, 0);
        System.out.println(max_len);
    }
}

